// Ensure we received input items from the Slack Trigger
if (!$input) {
  return [{ json: { status: "failed", reason: "No data received from Slack trigger." } }];
}

const text =$input.first().json.text ;
const files = $input.first().json.files|| [];

// 1. Validation Logic
const isTextValid = text.trim().length > 12;
const hasImages = files.length > 0;

// 2. Conditional Output If validation fails
if (!isTextValid || !hasImages) {
  let failureReason = "";
  if (!isTextValid && !hasImages) failureReason = "Text is too short (under 12 chars) and no images found.";
  else if (!isTextValid) failureReason = "Text is too short (must be more than 12 characters).";
  else failureReason = "No images found in the message.";

  return [{
    json: {
      status: "failed",
      reason: failureReason,
      text: text,
      files_count: files.length
    }
  }];
}

// 3. Return formatted payload if validation succeeds
return [{
  json: {
    status: "success",
    text: text.trim(),
    files: files.map(file => (
     file.url_private
    ))
  }
}];

let status_code = 200; 

// Collect all uploaded image URLs from Cloudinary
const imageUrls = $input.all()
  .map(item => item.json.secure_url || item.json.url)
  .filter(Boolean);

// Get the original article text from the validation node
const articleText = $('Code in JavaScript').first().json.text || "";

// Validate inputs
if (articleText === "" || imageUrls.length === 0) {
  status_code = 500;
}

// Create the combined string for the LLM
const userPrompt = JSON.stringify({
  status_code: status_code,
  articleText: articleText,
  imageUrls: imageUrls
}, null, 2);

return [{
  json: {
    status_code,
    articleText,
    imageUrls,
    userPrompt
  }
}];

